#include<bits/stdc++.h>
using namespace std;

list<int>::iterator it[100005];
list<int> q;

int main() {
    int Q;
    cin >> Q;
    while(q--)
    {
    q.clear();
	int n, m;
	cin >> n >> m;
	for(int i = 1; i <= n; i++)
		q.push_back(i);
	for(auto i = q.begin(); i != q.end(); i++)
		it[*i] = i;
	bool rev = 0;
	while(m--)
	{
		int op, x, y;
		cin >> op;
		if(rev && op < 3)
			op = 3 - op;
		if(op == 1)
		{
			cin >> x >> y;
			q.erase(it[x]);
			it[x] = q.insert(it[y], x);
		}
		if(op == 2)
		{
			cin >> x >> y;
			q.erase(it[x]);
			auto tmp = it[y];
			it[x] = q.insert(++tmp, x);
		}
		if(op == 3)
		{
			cin >> x >> y;
			swap(*it[x], *it[y]);
			swap(it[x], it[y]);

		}
		if(op == 4)
			rev = !rev;
	}
	if(rev)
		q.reverse();
	long long t = 0, ans = 0;
	for(int i : q)
	{
		t++;
		if(t % 2 == 1)
			ans += i;
	}
	cout << ans << endl;
    }
    return 0;
}
